INSERT INTO mock_tests (title, type, duration_minutes, questions) VALUES ('Frontend Mastery (React & Advanced JS)', 'TECHNICAL', 45, '[{"id": 1, "question": "Which of the following is true regarding React''s reconciliation algorithm?", "options": ["It compares the current DOM with the new DOM", "It compares the Virtual DOM with the real DOM", "It uses a heuristic O(n) algorithm to compare two React element trees", "It uses an O(n^3) algorithm for complete accuracy"], "answer": "It uses a heuristic O(n) algorithm to compare two React element trees"}, {"id": 2, "question": "What is the primary difference between useMemo and useCallback?", "options": ["useMemo memoizes a function, useCallback memoizes a value", "useMemo memoizes a value, useCallback memoizes a function", "useMemo is for synchronous operations, useCallback for async", "There is no difference, they are aliases"], "answer": "useMemo memoizes a value, useCallback memoizes a function"}, {"id": 3, "question": "In JavaScript, how does the Event Loop handle Macrotasks and Microtasks?", "options": ["It executes one Macrotask, then empties the Microtask queue", "It executes all Macrotasks, then all Microtasks", "Microtasks and Macrotasks are executed in random order based on priority", "It executes one Microtask, then empties the Macrotask queue"], "answer": "It executes one Macrotask, then empties the Microtask queue"}, {"id": 4, "question": "What does the ''use strict'' directive do in JavaScript?", "options": ["Enforces strict typing similar to TypeScript", "Eliminates some JavaScript silent errors by changing them to throw errors", "Prevents the use of async/await", "Forces all functions to be pure functions"], "answer": "Eliminates some JavaScript silent errors by changing them to throw errors"}, {"id": 5, "question": "How do you prevent a component from re-rendering in React if its props haven''t changed?", "options": ["Use React.PureComponent for class components or React.memo for functional components", "Use the usePreventRender hook", "Return false in the useEffect cleanup function", "Wrap the component in a Fragment"], "answer": "Use React.PureComponent for class components or React.memo for functional components"}, {"id": 6, "question": "What is the output of `typeof null` in JavaScript?", "options": ["''null''", "''object''", "''undefined''", "''boolean''"], "answer": "''object''"}, {"id": 7, "question": "In React, what is the purpose of the ''key'' prop when rendering lists?", "options": ["To provide a unique id for styling in CSS", "To help React identify which items have changed, are added, or are removed during reconciliation", "To securely encrypt the list items", "To index the items for faster search"], "answer": "To help React identify which items have changed, are added, or are removed during reconciliation"}, {"id": 8, "question": "What is a closure in JavaScript?", "options": ["A function that takes another function as an argument", "A function bundled together with references to its surrounding state (lexical environment)", "A block of code that executes immediately", "A method to close a database connection"], "answer": "A function bundled together with references to its surrounding state (lexical environment)"}, {"id": 9, "question": "Which React hook is used to access the context value without using a Context.Consumer?", "options": ["useContext", "useReducer", "useRef", "useProvider"], "answer": "useContext"}, {"id": 10, "question": "What is the phenomenon called when variables declared with ''var'' are moved to the top of their scope?", "options": ["Hoisting", "Bubbling", "Capturing", "Shadowing"], "answer": "Hoisting"}, {"id": 11, "question": "In React 18, what new feature allows you to mark state updates as non-urgent?", "options": ["useDeferredValue", "useTransition", "useId", "useMutableSource"], "answer": "useTransition"}, {"id": 12, "question": "How does JavaScript handle concurrency despite being single-threaded?", "options": ["By creating multiple Web Workers implicitly", "Through the Event Loop and asynchronous callbacks", "By utilizing multiple CPU cores automatically", "It doesn''t support concurrency"], "answer": "Through the Event Loop and asynchronous callbacks"}, {"id": 13, "question": "What is the purpose of ''forwardRef'' in React?", "options": ["To automatically forward props to child components", "To allow components to take a ref and pass it further down to a child", "To reference the previous state of a component", "To redirect routes in React Router"], "answer": "To allow components to take a ref and pass it further down to a child"}, {"id": 14, "question": "Which of the following methods mutates the original array in JavaScript?", "options": ["Array.prototype.map()", "Array.prototype.filter()", "Array.prototype.splice()", "Array.prototype.slice()"], "answer": "Array.prototype.splice()"}, {"id": 15, "question": "What is ''prop drilling'' in React?", "options": ["A technique to optimize rendering speed", "The process of passing props deeply through a component tree to a child component", "A security vulnerability involving component props", "Extracting props into a separate file"], "answer": "The process of passing props deeply through a component tree to a child component"}, {"id": 16, "question": "How can you deeply clone an object in JavaScript without external libraries?", "options": ["Object.assign({}, obj)", "{ ...obj }", "JSON.parse(JSON.stringify(obj))", "Object.create(obj)"], "answer": "JSON.parse(JSON.stringify(obj))"}, {"id": 17, "question": "What is the significance of the dependency array in useEffect?", "options": ["It determines the rendering priority of the component", "It specifies the DOM elements the effect interacts with", "It controls when the effect runs by checking if listed values have changed", "It limits the memory usage of the effect"], "answer": "It controls when the effect runs by checking if listed values have changed"}, {"id": 18, "question": "What is a ''Promise'' in JavaScript?", "options": ["A guarantee that a function will not throw an error", "An object representing the eventual completion or failure of an asynchronous operation", "A synchronous method to pause execution until data is ready", "A design pattern for creating classes"], "answer": "An object representing the eventual completion or failure of an asynchronous operation"}, {"id": 19, "question": "In Redux, what is a ''reducer''?", "options": ["A function that dispatches actions to the store", "A pure function that takes the previous state and an action, and returns the next state", "A middleware that intercepts API calls", "A component that connects React to the store"], "answer": "A pure function that takes the previous state and an action, and returns the next state"}, {"id": 20, "question": "What is the difference between ''=='' and ''==='' in JavaScript?", "options": ["''=='' compares references, ''==='' compares values", "''=='' performs type coercion before comparison, ''==='' does not", "There is no difference, they are interchangeable", "''==='' is used only for object comparison"], "answer": "''=='' performs type coercion before comparison, ''==='' does not"}, {"id": 21, "question": "What is Server-Side Rendering (SSR) in the context of React (e.g., using Next.js)?", "options": ["Rendering the HTML on the server and sending a fully populated page to the client", "Downloading all React components as a bundle before rendering", "Using a Node.js server to host the static build files", "Executing API calls solely on the client side"], "answer": "Rendering the HTML on the server and sending a fully populated page to the client"}, {"id": 22, "question": "What does the CSS property ''box-sizing: border-box'' do?", "options": ["Includes padding and border in the element''s total width and height", "Adds a border around the entire layout box", "Calculates width and height exclusive of padding", "Transforms the element into a flexbox container"], "answer": "Includes padding and border in the element''s total width and height"}, {"id": 23, "question": "Which array method is used to reduce the array to a single value?", "options": ["map()", "filter()", "reduce()", "forEach()"], "answer": "reduce()"}, {"id": 24, "question": "In React, what happens when you call setState()?", "options": ["React immediately updates the state and re-renders the component synchronously", "React merges the object into current state and schedules a re-render", "React overwrites the entire state object immediately", "React throws an error if called inside a functional component"], "answer": "React merges the object into current state and schedules a re-render"}, {"id": 25, "question": "What is ''event delegation'' in JavaScript?", "options": ["Assigning a single event listener to a parent element to handle events from its children", "Passing event objects as arguments to functions", "Using third-party libraries to manage events", "Delegating event processing to a Web Worker"], "answer": "Assigning a single event listener to a parent element to handle events from its children"}, {"id": 26, "question": "What is a ''Higher-Order Component'' (HOC) in React?", "options": ["A component that renders a complex UI", "A component that manages global state", "A function that takes a component and returns a new component", "A root component in the application tree"], "answer": "A function that takes a component and returns a new component"}, {"id": 27, "question": "What does ''NaN'' stand for and what is its type in JavaScript?", "options": ["Not a Number, type is ''string''", "Not a Null, type is ''object''", "Not a Number, type is ''number''", "Null and None, type is ''undefined''"], "answer": "Not a Number, type is ''number''"}, {"id": 28, "question": "How does ''useRef'' differ from ''useState''?", "options": ["useRef triggers a re-render when its value changes, useState does not", "useRef holds a mutable value that does not cause re-renders when changed", "useState is for DOM elements only, useRef is for data", "There is no functional difference"], "answer": "useRef holds a mutable value that does not cause re-renders when changed"}, {"id": 29, "question": "What is the purpose of a ''Service Worker'' in a web application?", "options": ["To handle database queries on the server", "To provide background sync and offline capabilities by intercepting network requests", "To serve CSS and image files faster", "To replace the main JavaScript thread"], "answer": "To provide background sync and offline capabilities by intercepting network requests"}, {"id": 30, "question": "In modern JavaScript, what is the syntax to import a default export from a module?", "options": ["import { module } from ''file''", "import module from ''file''", "import * as module from ''file''", "require(''file'')"], "answer": "import module from ''file''"}]');
INSERT INTO mock_tests (title, type, duration_minutes, questions) VALUES ('Backend Architecture & Engineering', 'TECHNICAL', 45, '[{"id": 1, "question": "In Java, what is the difference between a Checked and an Unchecked Exception?", "options": ["Checked exceptions are evaluated at compile time; Unchecked exceptions occur at runtime", "Checked exceptions inherit from Error; Unchecked inherit from Exception", "Unchecked exceptions must be declared in a method''s throws clause", "There is no difference in modern Java"], "answer": "Checked exceptions are evaluated at compile time; Unchecked exceptions occur at runtime"}, {"id": 2, "question": "What is the default scope of a Spring Bean?", "options": ["Prototype", "Singleton", "Request", "Session"], "answer": "Singleton"}, {"id": 3, "question": "In SQL, what is the primary difference between a clustered and a non-clustered index?", "options": ["A clustered index defines the physical sorting order of data rows; non-clustered creates a separate logical sorting structure", "A non-clustered index is faster for INSERT operations", "A table can have multiple clustered indexes but only one non-clustered", "Clustered indexes only apply to string columns"], "answer": "A clustered index defines the physical sorting order of data rows; non-clustered creates a separate logical sorting structure"}, {"id": 4, "question": "What does the ''volatile'' keyword do in Java?", "options": ["Makes a variable immutable", "Ensures that a variable''s value is always read from and written to main memory, preventing thread caching", "Synchronizes an entire method", "Prevents a variable from being serialized"], "answer": "Ensures that a variable''s value is always read from and written to main memory, preventing thread caching"}, {"id": 5, "question": "What is Dependency Injection in the context of Spring Framework?", "options": ["A design pattern where an object receives other objects that it depends on from an external source (IoC container)", "A method to inject SQL commands into a database", "A technique to inject malicious code for security testing", "Downloading dependencies automatically via Maven"], "answer": "A design pattern where an object receives other objects that it depends on from an external source (IoC container)"}, {"id": 6, "question": "What is the ACID property that ensures a transaction is all-or-nothing?", "options": ["Atomicity", "Consistency", "Isolation", "Durability"], "answer": "Atomicity"}, {"id": 7, "question": "In Java 8, what is an Optional used for?", "options": ["To handle optional method parameters", "To encapsulate a value that may or may not be present, reducing NullPointerExceptions", "To denote that a class can be subclassed", "To optimize garbage collection for specific objects"], "answer": "To encapsulate a value that may or may not be present, reducing NullPointerExceptions"}, {"id": 8, "question": "Which Spring Boot annotation combines @Configuration, @EnableAutoConfiguration, and @ComponentScan?", "options": ["@SpringBootApplication", "@SpringContext", "@EnableSpringBoot", "@ApplicationBootstrap"], "answer": "@SpringBootApplication"}, {"id": 9, "question": "What is a ''Deadlock'' in multithreading?", "options": ["When a thread terminates unexpectedly", "When two or more threads are blocked forever, waiting for each other to release resources", "When a thread is starved of CPU time", "When multiple threads execute the exact same instruction simultaneously"], "answer": "When two or more threads are blocked forever, waiting for each other to release resources"}, {"id": 10, "question": "In a relational database, what is normalization?", "options": ["The process of organizing data to minimize redundancy and improve data integrity", "The process of converting all strings to lowercase", "Denormalizing tables for faster read performance", "Encrypting database columns"], "answer": "The process of organizing data to minimize redundancy and improve data integrity"}, {"id": 11, "question": "What is the purpose of the ''transient'' keyword in Java?", "options": ["To mark a variable to be ignored during serialization", "To create a short-lived thread", "To indicate a variable whose value changes frequently", "To prevent inheritance of a class"], "answer": "To mark a variable to be ignored during serialization"}, {"id": 12, "question": "In Spring MVC, what is the role of the DispatcherServlet?", "options": ["It connects to the database", "It acts as the Front Controller, routing incoming HTTP requests to appropriate handlers", "It renders HTML views directly", "It manages Spring Security filters"], "answer": "It acts as the Front Controller, routing incoming HTTP requests to appropriate handlers"}, {"id": 13, "question": "What is an N+1 query problem in ORMs like Hibernate?", "options": ["When an application executes N queries to fetch N rows, plus 1 initial query to fetch the list of IDs", "When a database requires N+1 seconds to execute a query", "When a table joins with N other tables", "When an index is missing on N+1 columns"], "answer": "When an application executes N queries to fetch N rows, plus 1 initial query to fetch the list of IDs"}, {"id": 14, "question": "How does the Java Garbage Collector handle circular references?", "options": ["It leaks memory indefinitely", "It uses a mark-and-sweep algorithm starting from GC Roots, identifying unreachable cycles", "It throws a StackOverflowError", "It relies on reference counting to decrement them"], "answer": "It uses a mark-and-sweep algorithm starting from GC Roots, identifying unreachable cycles"}, {"id": 15, "question": "What is the difference between @RestController and @Controller in Spring?", "options": ["@RestController includes @ResponseBody on all handler methods automatically", "@Controller is used for REST APIs, @RestController for HTML pages", "There is no difference", "@RestController cannot be used with JSON data"], "answer": "@RestController includes @ResponseBody on all handler methods automatically"}, {"id": 16, "question": "Which SQL JOIN returns all rows from the left table and matched rows from the right table?", "options": ["INNER JOIN", "RIGHT JOIN", "LEFT JOIN", "FULL OUTER JOIN"], "answer": "LEFT JOIN"}, {"id": 17, "question": "What is the difference between StringBuffer and StringBuilder in Java?", "options": ["StringBuffer is thread-safe (synchronized), StringBuilder is not", "StringBuilder is thread-safe (synchronized), StringBuffer is not", "StringBuffer is used for numbers, StringBuilder for strings", "StringBuilder creates immutable objects"], "answer": "StringBuffer is thread-safe (synchronized), StringBuilder is not"}, {"id": 18, "question": "In Spring Boot, what is the purpose of the ''application.properties'' or ''application.yml'' file?", "options": ["To write unit tests", "To define application configuration properties like server port, database URLs, and custom settings", "To store HTML templates", "To declare Maven dependencies"], "answer": "To define application configuration properties like server port, database URLs, and custom settings"}, {"id": 19, "question": "What is a Database Transaction Isolation Level?", "options": ["A setting that controls the degree to which a transaction is isolated from the data and resource modifications made by other concurrent transactions", "A physical separation of database servers", "A security firewall for the database", "A method to backup data while it''s being written"], "answer": "A setting that controls the degree to which a transaction is isolated from the data and resource modifications made by other concurrent transactions"}, {"id": 20, "question": "What does the ''final'' keyword do when applied to a Java class?", "options": ["Allows the class to have abstract methods", "Prevents the class from being subclassed (inherited)", "Makes all variables in the class static", "Ensures the class is a singleton"], "answer": "Prevents the class from being subclassed (inherited)"}, {"id": 21, "question": "What is a ''Bean'' in Spring terminology?", "options": ["A java bean component", "An object that is instantiated, assembled, and managed by a Spring IoC container", "A database connection object", "A unit test case"], "answer": "An object that is instantiated, assembled, and managed by a Spring IoC container"}, {"id": 22, "question": "What is the purpose of the ''GROUP BY'' clause in SQL?", "options": ["To sort the result set in ascending order", "To filter rows before they are grouped", "To arrange identical data into groups, often used with aggregate functions like COUNT, MAX, SUM", "To join multiple tables together"], "answer": "To arrange identical data into groups, often used with aggregate functions like COUNT, MAX, SUM"}, {"id": 23, "question": "In Java, what is Type Erasure?", "options": ["The process where generic type information is removed at compile-time to ensure backward compatibility", "A feature to delete unused variables automatically", "A method to cast objects without compilation errors", "The clearing of memory allocated to specific types"], "answer": "The process where generic type information is removed at compile-time to ensure backward compatibility"}, {"id": 24, "question": "How do you handle transactions declaratively in Spring?", "options": ["By manually calling connection.commit()", "Using the @Transactional annotation", "By implementing the TransactionManager interface", "Spring handles all methods transactionally by default"], "answer": "Using the @Transactional annotation"}, {"id": 25, "question": "What is a SQL View?", "options": ["A physical copy of data stored on disk", "A graphical user interface for a database", "A virtual table based on the result-set of an SQL statement", "A trigger that executes after an INSERT"], "answer": "A virtual table based on the result-set of an SQL statement"}, {"id": 26, "question": "Which collection implements a FIFO (First-In, First-Out) data structure in Java?", "options": ["Stack", "Queue", "HashSet", "TreeMap"], "answer": "Queue"}, {"id": 27, "question": "What is Cross-Origin Resource Sharing (CORS)?", "options": ["A database replication strategy", "A security feature that allows restricted resources on a web page to be requested from another domain", "A method to share code between backend and frontend", "A load balancing technique"], "answer": "A security feature that allows restricted resources on a web page to be requested from another domain"}, {"id": 28, "question": "What is the ''HAVING'' clause used for in SQL?", "options": ["To filter records based on aggregate functions (used after GROUP BY)", "To replace the WHERE clause entirely", "To sort the final result set", "To specify columns to select"], "answer": "To filter records based on aggregate functions (used after GROUP BY)"}, {"id": 29, "question": "What is the main advantage of a Microservices architecture over a Monolith?", "options": ["It is always faster to develop initially", "Independent deployment, scalability, and technology diversity of services", "Requires less network overhead", "It simplifies database transactions"], "answer": "Independent deployment, scalability, and technology diversity of services"}, {"id": 30, "question": "What does the ''equals()'' method in the Object class check by default in Java?", "options": ["Value equality", "Reference equality (memory address)", "Hash code equality", "Class type equality"], "answer": "Reference equality (memory address)"}]');
INSERT INTO mock_tests (title, type, duration_minutes, questions) VALUES ('Cloud & DevOps Engineering', 'TECHNICAL', 45, '[{"id": 1, "question": "In Docker, what is the difference between an Image and a Container?", "options": ["An image is a running instance of a container", "An image is a read-only template, a container is a runnable instance of an image", "They are identical terms", "An image is used for Linux, a container for Windows"], "answer": "An image is a read-only template, a container is a runnable instance of an image"}, {"id": 2, "question": "What is the primary function of Kubernetes?", "options": ["To compile source code into binaries", "To automate deployment, scaling, and management of containerized applications", "To provision virtual machines on AWS", "To act as a relational database"], "answer": "To automate deployment, scaling, and management of containerized applications"}, {"id": 3, "question": "In AWS, what is a VPC (Virtual Private Cloud)?", "options": ["A physical server dedicated to a single customer", "A logically isolated virtual network where you can launch AWS resources", "A managed database service", "A content delivery network"], "answer": "A logically isolated virtual network where you can launch AWS resources"}, {"id": 4, "question": "What is the purpose of a Dockerfile?", "options": ["To manage Kubernetes clusters", "A text document containing all the commands a user could call on the command line to assemble an image", "To store application logs", "To monitor container performance"], "answer": "A text document containing all the commands a user could call on the command line to assemble an image"}, {"id": 5, "question": "What is a Kubernetes ''Pod''?", "options": ["A virtual machine managed by Kubernetes", "The smallest deployable computing unit in Kubernetes, consisting of one or more containers sharing network and storage", "A load balancer", "A persistent storage volume"], "answer": "The smallest deployable computing unit in Kubernetes, consisting of one or more containers sharing network and storage"}, {"id": 6, "question": "Which AWS service is specifically designed for serverless compute?", "options": ["Amazon EC2", "AWS Lambda", "Amazon RDS", "Amazon S3"], "answer": "AWS Lambda"}, {"id": 7, "question": "What is Infrastructure as Code (IaC)?", "options": ["Writing application logic directly on servers", "Managing and provisioning computing infrastructure through machine-readable definition files (e.g., Terraform)", "Using APIs to execute manual server updates", "Coding inside a cloud-based IDE"], "answer": "Managing and provisioning computing infrastructure through machine-readable definition files (e.g., Terraform)"}, {"id": 8, "question": "In CI/CD, what does ''CI'' stand for and mean?", "options": ["Continuous Integration: the practice of merging all developers'' working copies to a shared mainline several times a day", "Cloud Infrastructure: provisioning servers automatically", "Continuous Iteration: writing code in sprints", "Constant Installation: installing software directly to production"], "answer": "Continuous Integration: the practice of merging all developers'' working copies to a shared mainline several times a day"}, {"id": 9, "question": "What is an Amazon S3 bucket?", "options": ["A block storage volume attached to an EC2 instance", "A fully managed relational database", "A highly available object storage service used to store and retrieve any amount of data", "A load balancer configuration"], "answer": "A highly available object storage service used to store and retrieve any amount of data"}, {"id": 10, "question": "How does Kubernetes ensure high availability if a node fails?", "options": ["By automatically migrating the physical hardware", "By relying on AWS to reboot the node", "Through the ReplicaSet/Deployment controller which reschedules the failed Pods onto healthy nodes", "By storing a backup on S3"], "answer": "Through the ReplicaSet/Deployment controller which reschedules the failed Pods onto healthy nodes"}, {"id": 11, "question": "What is the purpose of a .dockerignore file?", "options": ["To ignore certain containers from running", "To specify files and directories that should be excluded from the Docker build context, reducing image size", "To ignore build errors", "To hide source code from GitHub"], "answer": "To specify files and directories that should be excluded from the Docker build context, reducing image size"}, {"id": 12, "question": "Which AWS service acts as a Content Delivery Network (CDN)?", "options": ["Amazon Route 53", "Amazon CloudFront", "Amazon API Gateway", "Amazon VPC"], "answer": "Amazon CloudFront"}, {"id": 13, "question": "What is a Kubernetes ''Service''?", "options": ["A background process running on a node", "An abstract way to expose an application running on a set of Pods as a network service (e.g., providing a stable IP)", "A physical network router", "A billing tier in GCP"], "answer": "An abstract way to expose an application running on a set of Pods as a network service (e.g., providing a stable IP)"}, {"id": 14, "question": "What is Terraform used for?", "options": ["Building Docker images", "Managing Infrastructure as Code across multiple cloud providers", "Application performance monitoring", "Continuous integration testing"], "answer": "Managing Infrastructure as Code across multiple cloud providers"}, {"id": 15, "question": "In AWS IAM, what is the principle of ''least privilege''?", "options": ["Granting all users administrator access for efficiency", "Granting only the permissions required to perform a specific task", "Using the cheapest available EC2 instance", "Applying permissions only to root accounts"], "answer": "Granting only the permissions required to perform a specific task"}, {"id": 16, "question": "What does a Docker volume do?", "options": ["Increases the container''s RAM allocation", "Provides a mechanism for persisting data generated by and used by Docker containers, independent of the container lifecycle", "Manages network traffic between containers", "Encrypts container data automatically"], "answer": "Provides a mechanism for persisting data generated by and used by Docker containers, independent of the container lifecycle"}, {"id": 17, "question": "What is blue/green deployment?", "options": ["A deployment strategy that gradually shifts traffic based on color preferences", "A technique that reduces downtime by running two identical environments (blue and green); only one serves live traffic at a time", "Deploying code without testing", "A database replication method"], "answer": "A technique that reduces downtime by running two identical environments (blue and green); only one serves live traffic at a time"}, {"id": 18, "question": "What is Amazon Route 53?", "options": ["A managed message queue service", "A highly available and scalable cloud Domain Name System (DNS) web service", "A virtual private network (VPN) service", "A container orchestration service"], "answer": "A highly available and scalable cloud Domain Name System (DNS) web service"}, {"id": 19, "question": "In Kubernetes, what is a ''ConfigMap'' used for?", "options": ["Storing encrypted passwords and tokens", "Decoupling environment-specific configuration data from container images", "Routing external traffic into the cluster", "Scheduling Pods to specific nodes"], "answer": "Decoupling environment-specific configuration data from container images"}, {"id": 20, "question": "What is the main benefit of using a multi-stage Docker build?", "options": ["It runs containers in multiple stages sequentially", "It creates smaller final images by separating the build environment from the runtime environment", "It bypasses network security checks", "It automatically pushes the image to multiple registries"], "answer": "It creates smaller final images by separating the build environment from the runtime environment"}, {"id": 21, "question": "What is an AWS EC2 Auto Scaling Group?", "options": ["A feature that automatically scales the size of an S3 bucket", "A service that automatically adjusts the number of EC2 instances in a group based on demand or schedules", "A database scaling tool", "A method for automatically updating application code"], "answer": "A service that automatically adjusts the number of EC2 instances in a group based on demand or schedules"}, {"id": 22, "question": "What is Prometheus primarily used for in a DevOps ecosystem?", "options": ["Storing container images", "Systems and service monitoring, specifically metrics collection and alerting", "Automated code formatting", "Managing DNS records"], "answer": "Systems and service monitoring, specifically metrics collection and alerting"}, {"id": 23, "question": "What is an Ingress in Kubernetes?", "options": ["A node that processes external API requests", "An API object that manages external access to the services in a cluster, typically HTTP/HTTPS, providing load balancing and SSL termination", "A physical network cable connecting clusters", "A persistent storage volume"], "answer": "An API object that manages external access to the services in a cluster, typically HTTP/HTTPS, providing load balancing and SSL termination"}, {"id": 24, "question": "Which of the following describes AWS CloudFormation?", "options": ["A service to monitor application logs", "AWS''s native Infrastructure as Code service that models and sets up AWS resources", "A content delivery network", "A managed Kubernetes service"], "answer": "AWS''s native Infrastructure as Code service that models and sets up AWS resources"}, {"id": 25, "question": "What is the role of the ''kubelet'' in a Kubernetes cluster?", "options": ["It acts as the primary datastore (etcd)", "It is an agent that runs on each node in the cluster and ensures containers are running in a Pod", "It exposes services to the external internet", "It schedules pods to nodes based on resource availability"], "answer": "It is an agent that runs on each node in the cluster and ensures containers are running in a Pod"}, {"id": 26, "question": "What does it mean when a Docker container is ''stateless''?", "options": ["It has no IP address", "It does not save data or state locally across restarts; any persistent data must be stored externally (e.g., in a database or volume)", "It does not consume CPU resources", "It cannot connect to the internet"], "answer": "It does not save data or state locally across restarts; any persistent data must be stored externally (e.g., in a database or volume)"}, {"id": 27, "question": "What is ''GitOps''?", "options": ["A version control system created by Ops teams", "A set of practices that uses Git repositories as the single source of truth to deliver infrastructure and application configurations declaratively", "A command-line tool for git", "A database management strategy"], "answer": "A set of practices that uses Git repositories as the single source of truth to deliver infrastructure and application configurations declaratively"}, {"id": 28, "question": "In AWS, what is a Security Group?", "options": ["A team responsible for AWS compliance", "A virtual firewall that controls inbound and outbound traffic for EC2 instances", "An encryption key management service", "A load balancer configuration"], "answer": "A virtual firewall that controls inbound and outbound traffic for EC2 instances"}, {"id": 29, "question": "What is a Helm chart?", "options": ["A dashboard for Kubernetes metrics", "A collection of files that describe a related set of Kubernetes resources, acting as a package manager for Kubernetes", "A network routing protocol", "A type of container image"], "answer": "A collection of files that describe a related set of Kubernetes resources, acting as a package manager for Kubernetes"}, {"id": 30, "question": "What is the primary difference between a Virtual Machine (VM) and a Container?", "options": ["Containers run on physical hardware without an OS", "VMs virtualize the hardware (each needs a full guest OS); Containers virtualize the OS layer (sharing the host OS kernel)", "VMs are faster to start than containers", "Containers are only used for web servers"], "answer": "VMs virtualize the hardware (each needs a full guest OS); Containers virtualize the OS layer (sharing the host OS kernel)"}]');
